var formatted = formatter.format(date);
var datePart = formatted.slice(0, 10);
var timePart = formatted.slice(11, 19);

function trimText(value) {
  return String(value || "").trim();
}

function startsWithLower(value, prefix) {
  return String(value || "").toLowerCase().indexOf(prefix) === 0;
}

function cleanTitle(value) {
  var input = String(value || "");
  var output = "";
  for (var i = 0; i < input.length; i++) {
    var ch = input.charAt(i);
    var code = input.charCodeAt(i);
    if (code < 32 || code > 126) {
      continue;
    }
    if (code === 34 || code === 35 || code === 42 || code === 47 || code === 58 || code === 60 || code === 62 || code === 63 || code === 91 || code === 92 || code === 93 || code === 94 || code === 124) {
      continue;
    }
    output += ch;
  }
  while (output.indexOf("  ") !== -1) {
    output = output.split("  ").join(" ");
  }
  return output.trim().slice(0, 80);
}

function firstSentence(value) {
  var text = trimText(value).split(String.fromCharCode(10)).join(" ");
  while (text.indexOf("  ") !== -1) {
    text = text.split("  ").join(" ");
  }
  var stops = [". ", "? ", "! "];
  var end = -1;
  for (var i = 0; i < stops.length; i++) {
    var pos = text.indexOf(stops[i]);
    if (pos !== -1 && (end === -1 || pos < end)) {
      end = pos + 1;
    }
  }
  if (end === -1 || end > 240) {
    return text.slice(0, 240).trim();
  }
  return text.slice(0, end).trim();
}

function findUrl(value) {
  var pieces = String(value || "").split(" ");
  for (var i = 0; i < pieces.length; i++) {
    var p = pieces[i].trim();
    if (p.indexOf("http://") === 0 || p.indexOf("https://") === 0) {
      while (p.endsWith(".") || p.endsWith(",") || p.endsWith(")")) {
        p = p.slice(0, -1);
      }
      return p;
    }
  }
  return "";
}

function extractManualTitleAndContent(value) {
  var allText = String(value || "");
  var lowerAll = trimText(allText).toLowerCase();
  var prefixes = ["de titel is", "titel", "title"];
  for (var prefIndex = 0; prefIndex < prefixes.length; prefIndex++) {
    var prefix = prefixes[prefIndex];
    if (lowerAll.indexOf(prefix) === 0) {
      var rest = trimText(allText.slice(prefix.length));
      while (rest.charAt(0) === ":" || rest.charAt(0) === "-" || rest.charAt(0) === "=") {
        rest = trimText(rest.slice(1));
      }
      var cut = rest.indexOf(String.fromCharCode(10));
      var dot = rest.indexOf(". ");
      if (cut === -1 || (dot !== -1 && dot < cut)) {
        cut = dot === -1 ? cut : dot + 1;
      }
      var titlePart = cut === -1 ? rest : rest.slice(0, cut);
      var contentPart = cut === -1 ? "" : rest.slice(cut);
      titlePart = trimText(titlePart);
      contentPart = trimText(contentPart);
      if (titlePart.endsWith(".")) {
        titlePart = trimText(titlePart.slice(0, -1));
      }
      return { manualTitle: titlePart, content: contentPart };
    }
  }
  var linesIn = allText.split(String.fromCharCode(10));
  var manualTitle = "";
  var contentLines = [];
  for (var i = 0; i < linesIn.length; i++) {
    var line = linesIn[i];
    var lowered = trimText(line).toLowerCase();
    if (!manualTitle && (lowered.indexOf("titel:") === 0 || lowered.indexOf("title:") === 0 || lowered.indexOf("titel :") === 0 || lowered.indexOf("title :") === 0)) {
      manualTitle = trimText(line.slice(line.indexOf(":") + 1));
    } else {
      contentLines.push(line);
    }
  }
  return { manualTitle: manualTitle, content: trimText(contentLines.join(String.fromCharCode(10))) };
}

function yamlList(items) {
  var out = [];
  for (var i = 0; i < items.length; i++) {
    out.push("  - " + items[i]);
  }
  return out;
}

