const item = $input.first();
const input = item.json || {};
const message = input.message || input.edited_message || input.channel_post || input;
const document = message.document || {};
const thumb = document.thumbnail || {};
const caption = String(message.caption || '').trim();
const mimeType = String(document.mime_type || '').toLowerCase();
const originalName = String(document.file_name || 'remarkable.pdf');
const isPdf = document.file_id && (mimeType === 'application/pdf' || originalName.toLowerCase().endsWith('.pdf'));

if (!isPdf || !thumb.file_id) {
  return [];
}

function extractManualTitle(value) {
  const text = String(value || '').trim();
  const match = text.match(/^\s*(?:de titel is|titel|title)\s*[:\-=]?\s*(.+?)(?:\r?\n|\.\s+|$)/i);
  if (!match) return { title: '', rest: text };
  const title = match[1].trim().replace(/\.$/, '').trim();
  const rest = text.slice(match[0].length).trim();
  return { title, rest };
}

function slugify(value) {
  return String(value || 'remarkable-pdf')
    .normalize('NFD').replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 70) || 'remarkable-pdf';
}

const extracted = extractManualTitle(caption);
const now = new Date();
const datePart = now.toISOString().slice(0, 10);
const timePart = now.toTimeString().slice(0, 5).replace(':', '');
const baseName = slugify(extracted.title || caption || originalName.replace(/\.pdf$/i, '') || 'remarkable-pdf');
const pdfFileName = `${datePart}-${timePart}-${baseName}.pdf`;
const previewFileName = `${datePart}-${timePart}-${baseName}-preview.jpg`;

return [{
  json: {
    fileId: thumb.file_id,
    pdfFileId: document.file_id,
    originalFileName: originalName,
    pdfFileName,
    previewFileName,
    pdfWikiLink: `[[Remarkable/${pdfFileName}]]`,
    previewWikiLink: `![[Remarkable/${previewFileName}]]`,
    caption,
    cleanCaption: extracted.rest,
    manualTitle: extracted.title,
    chatId: message.chat && message.chat.id,
    messageId: message.message_id,
    from: message.from,
    created: now.toISOString(),
    localTime: now.toLocaleString('nl-NL', { timeZone: 'Europe/Amsterdam' })
  }
}];

const response = $input.first().json || {};
const responseTextForSkip = JSON.stringify(response);
if (responseTextForSkip.includes('SKIP_DIRECT_REMARKABLE_BRANCH_DO_NOT_WRITE')) {
  return [];
}

function fromNode(name) {
  try {
    return $(name).first().json || {};
  } catch (error) {
    return {};
  }
}

function getValue(obj, path) {
  return path.split('.').reduce(function(current, key) {
    if (current && Object.prototype.hasOwnProperty.call(current, key)) return current[key];
    return undefined;
  }, obj);
}

function cleanTitleLine(value) {
  return String(value || '')
    .replace(/^\s*titel\s*:?\s*/i, '')
    .replace(/^\s*title\s*:?\s*/i, '')
    .split('\n')[0]
    .trim();
}

function extractText(value) {
  if (typeof value.output_text === 'string') return value.output_text;
  if (Array.isArray(value.output)) {
    const parts = [];
    for (const outputItem of value.output) {
      if (typeof outputItem.content === 'string') parts.push(outputItem.content);
      if (Array.isArray(outputItem.content)) {
        for (const contentItem of outputItem.content) {
          if (typeof contentItem.text === 'string') parts.push(contentItem.text);
          if (typeof contentItem.output_text === 'string') parts.push(contentItem.output_text);
        }
      }
    }
    if (parts.length) return parts.join('\n\n');
  }
  if (Array.isArray(value.choices)) {
    return value.choices.map(function(choice) {
      if (choice.message && choice.message.content) return choice.message.content;
      if (choice.text) return choice.text;
      return '';
    }).filter(Boolean).join('\n\n');
  }
  return '';
}

function slugify(value) {
  return String(value || '')
    .normalize('NFKD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/^-+|-+$/g, '')
    .slice(0, 80) || 'remarkable-notitie';
}

function dateStamp(value) {
  const date = value ? new Date(value) : new Date();
  const pad = number => String(number).padStart(2, '0');
  return [date.getFullYear(), pad(date.getMonth() + 1), pad(date.getDate())].join('-') + '-' + pad(date.getHours()) + pad(date.getMinutes());
}

let analysis = extractText(response).trim();
analysis = analysis.replace(/^\`\`\`(?:markdown|md)?\s*/i, '').replace(/\`\`\`$/i, '').trim();
analysis = analysis.replace(/<br\s*\/?>/gi, '\n').replace(/<\/?(?:html|body|article|section|main|div|p)[^>]*>/gi, '\n').trim();
analysis = analysis.replace(/^#\s*File\s*\d+\s*\n+/i, '').trim();
analysis = analysis.replace(/^#\s*file[_ -]?\d+\s*\n+/i, '').trim();

if (!analysis) {
  throw new Error('OpenAI gaf geen analyse terug voor het reMarkable PDF-document.');
}

const telegram = fromNode('Telegram Trigger');
const oldMeta = fromNode('Prepare Remarkable PDF Preview');
const ocrPrepare = fromNode('Prepare Remarkable OCR Request');
const ocrMeta = ocrPrepare.meta || {};
const meta = Object.assign({}, ocrMeta, oldMeta);

const telegramDocumentName = getValue(telegram, 'message.document.file_name') || getValue(telegram, 'message.document.fileName');
const telegramCaption = getValue(telegram, 'message.caption') || '';
const messageDate = getValue(telegram, 'message.date');
const sourcePdfName = telegramDocumentName || oldMeta.fileName || oldMeta.originalFileName || ocrMeta.fileName || ocrMeta.originalFileName || 'remarkable.pdf';

const filenameTitle = String(sourcePdfName).replace(/\.pdf$/i, '');
const captionTitle = cleanTitleLine(telegramCaption);
const titleSource = captionTitle || oldMeta.title || oldMeta.caption || oldMeta.fileTitle || filenameTitle || ocrMeta.title || 'reMarkable notitie';
const rawTitle = String(titleSource)
  .replace(/^\d{4}-\d{2}-\d{2}-\d{4}-/i, '')
  .replace(/[-_]+/g, ' ')
  .trim();
